entry.content:
/*@import "black.css";*/
/*@import "next.css"*/

@import "add-on.css";
/*@import "spfk.css";*/

/* 单行代码框 加粗 边距 */
code,b,strong{
    margin: 0px 5px 0px 5px;
}

.digit{
    color: #fff;
    background-color: #727272;

    border-radius: 3px;
    padding: 2px 5px;

    vertical-align:super;
    font-size: 10px;
}

.id-card{
    display: block;
    margin: 50px;                   /* 外边距 */
    padding: 20px;                   /* 内边距 */
    width: 500px;                   /* 宽度 */
    height: 200px;                  /* 高度 */
    border: 1px solid #000;       /* 边框 */

    /* 圆角边框 */
    border-radius: 20px;
    -moz-border-radius: 20px;
    -webkit-border-radius: 20px;
}

.logo{
    display: inline;
    padding: 5px;
    width: 110px;
    height: auto;
    border: 1px solid #aaa;
    float: left;
}
.id-card img{
    width: 100px;
    height: 100px;
}
.information{
    display: inline;
    height: auto;
    padding: 5px 5px;
    margin: 0px 0px 0px 300px;
}
.information ul{
    list-style: none;
}

/* Bootstrap 部分 CSS 效果 */
kbd {
    font-family: Consolas;
	padding: 2px 4px;
	font-size: 90%;
	color: #fff;
	background-color: #000;
	border-radius: 3px;
	-webkit-box-shadow: inset 0 -1px 0 rgba(0,0,0,.25);
	box-shadow: inset 0 -1px 0 rgba(0,0,0,.25)
}

code{
    font-family: Consolas;
    color: #c7254e;
    background-color: #f9f2f4;
    margin: 0px 2px 0px 2px;
}
.label{
    font-family: Consolas;
    display: inline;
    color: #fff;
    padding: 1px 3px 2px 3px;
    margin: 0px 2px 0px 2px;
    border-radius: 2px;
}
.label-red{
    background: #d9534f;
}
.label-green{
    background: #5cb85c;
}
.label-blue{
    background: #428bca;
}
.label-sky{
    background: #5bc0de;
}
.label-orange{
    background: #f0ad4e;
}

/* OJ 题目部分 CSS 效果 */
.oj{
    display: block;
    background: #f7f7f7;
    color: #666;
    border-radius: 5px;
    padding: 5px 20px 5px 20px;
    height: 100%;
}
.part:before{
    content: attr(title);
    color: #444;
    font-weight: bold;
    font-size: 20px;
}
.clear {
        clear: both;
}
.samp{
    font-family: "Consolas";
    display: block;
}
.input,
.output{
    display: block;
    width: 45%;
    height: 100%;
}
.input{
    float: left;
}
.output{
    float: right;
}
.oj blockquote{
    /* 引用在 .oj 类中 显示颜色修改 */
    background: #888;
    color: #fff
}

/* 代码段部分隐藏 CSS 效果 */
.hider_title{
    font-family: "Microsoft Yahei";
    cursor: pointer;
    font-weight: bold;
    /* background-color: #555; */
    width: auto;
}
.fold_parent{
    padding: 5px;
    /* background-color: #555; */
    border-radius: 5px;
}
.close:after{
    content: "▼";
}
.open:after{
    content: "▲";
}

/* blockquote-center 标签 */
.blockquote-center {
  position: relative;
  margin: 40px 0;
  padding: 0;
  border-left: none;
  text-align: center;
}
.blockquote-center::before,
.blockquote-center::after {
    position: absolute;
    content: ' ';
    display: block;
    width: 100%;
    height: 24px;
    opacity: 0.2;
    background-repeat: no-repeat;
    background-position: 0 -6px;
    background-size: 22px 22px;
  }
.blockquote-center ::before {
    top: -20px;
    background-image: url($center-quote-left);
    border-top: 1px solid #666;
}
.blockquote-center::after {
    bottom: -20px;
    background-image: url($center-quote-right);
    border-bottom: 1px solid #666;
    background-position: 100% 8px;
  }

.blockquote-center p,
.blockquote-center div{
    text-align: center;
}


/* note 标签 */
.note {
  padding: 20px;
  margin: 20px 0;
  border: 1px solid #eee;
  border-left-width: 5px;
  border-radius: 3px;
}
.note h2,
.note h3,
.note h4,
.note h5,
.note h6 {
  margin-top: 0;
  margin-bottom: 5px;
}
.note p:last-child {
  margin-bottom: 0;
}
.note code {
  border-radius: 3px;
}
.note .note {
  margin-top: -5px;
}
.default {
  border-left-color: #777;
}
.default h2,
.default h3,
.default h4,
.default h5,
.default h6 {
  color: #777;
}
.primary {
  border-left-color: #428bca;
}
.primary h2,
.primary h3,
.primary h4,
.primary h5,
.primary h6 {
  color: #428bca;
}
.success {
  border-left-color: #5cb85c;
}
.success h2,
.success h3,
.success h4,
.success h5,
.success h6 {
  color: #5cb85c;
}
.danger {
  border-left-color: #d9534f;
}
.danger h2,
.danger h3,
.danger h4,
.danger h5,
.danger h6 {
  color: #d9534f;
}
.warning {
  border-left-color: #f0ad4e;
}
.warning h2,
.warning h3,
.warning h4,
.warning h5,
.warning h6 {
  color: #f0ad4e;
}
.info {
  border-left-color: #5bc0de;
}
.info h2,
.info h3,
.info h4,
.info h5,
.info h6 {
  color: #5bc0de;
}


.card-pool{
    columns: 200px;
    -moz-column: 200px;
    -webkit-column: 200px;
    -o-column: 200px;
}
.card-card {
    width: 200px;
    min-height: 100px;
    box-shadow: 2px 2px 6px #b5b5b5;
    padding: 20px 15px;
    margin: 10px;
    display: inline-block;
    font-size: 15px;
    background-color:#fff;
}
.card-head {
    padding: 10px;
    font-size: 13px;
}
.card-container {
    padding: 10px;
}
.card-foot {
    padding: 10px;
}

/*黑色主题*/
/*主题*/
body {
    color: #bbb;
    background: #333;
}

/*最顶部的header*/
.site-meta {
    background: #000
}

/*侧边栏 & 主体*/
.sidebar-inner,
.header-inner,
.content-wrap
{
    color: #bbb;
    background: #222
}



/*导航栏菜单*/
.menu .menu-item a:hover,
.menu-item-active a {
    background: #555;
    border-bottom-color: #6cf;
}
.menu-item-active a:after {
    background-color: #6cf;
}
.header a,
.sidebar a {
    color: #bbb;
}

/*post主体*/
.content-wrap
{
    color: #bbb;
}

/*单行代码块*/
code{
  color: #999;
  background: #444;
}

/*标题*/
.posts-expand .post-title-link,
.post-title,
.post-title-link{
    color: #fff
}


/*more*/
.btn:hover, .post-more-link .btn:hover {
    border-color: #555;
    color: #999;
    background: #555;
}
.post-more-link .btn {
    color: #fff;
    font-size: 14px;
    background: #777;
    border-radius: 2px;
    line-height: 2;
}

/*引用*/
blockquote {
    color: #bbb;
}

/*标签云*/
.tag-cloud-tags a{
    background: rgba(102,204,255,0.5);
    border-radius: 10px;
    padding: 5px;
}
.tag-cloud-tags a:hover{
    background: rgba(102,204,255,1);

}

.problem_title{
    color: blue;
    font-weight: bolder;
    font-size: 20px;
}

.problem_des{
    border-radius: 15px;
    border-style: dotted;
    padding: 10px;
    width: 100%;
    height: 100%;
    background-color: rgb(234, 235, 255);
}

